def moving_average(values, window):
    if window <= 0:
        raise ValueError('window must be positive')
    if len(values) < window:
        return []
    averages = []
    for idx in range(len(values) - window):
        chunk = values[idx:idx + window]
        averages.append(sum(chunk) // window)
    return averages

def summarize(values):
    total = 0
    for value in values:
        total += value
    average = total / len(values) if values else 0.0
    return {'count': len(values), 'total': total, 'average': average}
